                       </div>\r\n                        </td>\r\n                        <td>\r\n                            <el-button size=\"mini\" type=\"success\" style=\"margin-bottom:3px;\"\r\n                                @click=\"clickOpenWhatsapp(data)\">\r\n                                <i class=\"fab fa-whatsapp\" aria-hidden=\"true\"></i>\r\n                                \r\n                            </el-button>\r\n                            \r\n                            <el-button size=\"mini\" plain @click=\"\r\n                                print(data.external_id, data.document_type_id)\r\n                            \">\r\n                                <i class=\"fas fa-print\"></i> \r\n                            </el-button>\r\n                        </td>\r\n                        <td v-if=\"type == 'saleNotes'\">{{ data.full_number }}</td>\r\n                        <td v-else>{{ data.number }}</td>\r\n                        <td>{{ data.date_of_issue }}</td>\r\n                        <td>\r\n                            {{ data.customer_name }} <br />\r\n                            <span class=\"text-muted\">{{\r\n                                data.customer_number\r\n                            }}</span>\r\n                        </td>\r\n                        <td v-if=\"type == 'documents'\" :class=\"\r\n                            `${data.state_type_description == 'Aceptado'\r\n                                ? 'text-success'\r\n                                : data.state_type_description == 'Anulado'\r\n                                    ? 'text-danger'\r\n                                    : data.state_type_description == 'Enviado'\r\n                                        ? 'text-primary'\r\n                                        : 'text-black'\r\n                            }`\r\n                        \">\r\n                            <b> {{ data.state_type_description }}</b>\r\n                        </td>\r\n                        <td>\r\n                            {{ data.total }}\r\n                        </td>\r\n                        \r\n                        \r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n        </div>\r\n        <el-pagination @current-change=\"getRecords\" layout=\"total, prev, pager, next\" :total=\"pagination.total\"\r\n            :current-page.sync=\"pagination.current_page\" :page-size=\"pagination.per_page\"></el-pagination>\r\n        <whatsapp-modal :documentNumber=\"currentNumber\" :company=\"company\" :documentId=\"currentId\"\r\n            :documentTypeId=\"currentType\" :showDialog.sync=\"showWhatsappModal\" :sender=\"sender\">\r\n        </whatsapp-modal>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport whatsappModal from \"./whatsapp_modal.vue\";\r\nexport default {\r\n    components: { whatsappModal },\r\n    props: [\"records\", \"pagination\", \"type\", \"company\", \"sender\"],\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            showWhatsappModal: false,\r\n            currentId: null,\r\n            currentType: null,\r\n            currentNumber: null\r\n        };\r\n    },\r\n    \r\n    methods: {\r\n        clickOpenWhatsapp(record) {\r\n            this.showWhatsappModal = true;\r\n            this.currentId = record.id;\r\n            this.currentType = record.document_type_id;\r\n            if (this.type == \"saleNotes\") {\r\n                this.currentNumber = record.full_number;\r\n            } else {\r\n                this.currentNumber = record.number;\r\n            }\r\n        },\r\n        async clickSendOnline(document_id) {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.get(\r\n                    `/documents/send/${document_id}`\r\n                );\r\n\r\n                if (response.data.success) {\r\n                    this.$toast.success(\r\n                        \"Se envio satisfactoriamente el comprobante.\"\r\n                    );\r\n                    this.$eventHub.$emit(\"reloadData\");\r\n\r\n                    // this.clickCheckOnline(document_id);\r\n                } else {\r\n                    this.$toast.error(response.data.message);\r\n                }\r\n            } catch (error) {\r\n                this.$toast.error(error.response.data.message);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async clickReStore(document_id) {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.get(\r\n                    `/documents/re_store/${document_id}`\r\n                );\r\n                console.log(response);\r\n                if (response.data.success) {\r\n                    this.$toast.success(response.data.message);\r\n                } else {\r\n                    this.$toast.error(response.data.message);\r\n                }\r\n            } catch (error) {\r\n                this.$toast.error(error.response.data.message);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n\r\n        async clickValidarCpe(document_id) {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.get(\r\n                    `/documents/validate/${document_id}`\r\n                );\r\n\r\n                if (response.data.success) {\r\n                    this.$toast.success(response.data.message);\r\n                    this.$emit(\"getRecords\", this.pagination.current_page);\r\n                } else {\r\n                    this.$toast.error(response.data.message);\r\n                }\r\n            } catch (error) {\r\n                this.$toast.error(error.response.data.message);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        getRecords() {\r\n            this.$emit(\"getRecords\", this.pagination.current_page);\r\n        },\r\n        print(external_id, type) {\r\n            this.$emit(\"printData\", external_id, type);\r\n        }\r\n    }\r\n    \r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/document_print_detail.vue","<template>\r\n    <el-dialog :visible=\"showDialog\" append-to-body @close=\"close\" @open=\"open\" width=\"60%\" v-loading=\"loading\"  \r\n        title=\"Imprimir documento\">\r\n        <div class=\"card p-2\">\r\n            <div class=\"d-flex\">\r\n                <div class=\"col-6 p-1 col-md-3\">\r\n                    <el-select v-model=\"typeSearch\">\r\n                        <el-option value=\"document\" label=\"N° documento\">\r\n                        </el-option>\r\n                        <el-option value=\"client\" label=\"Cliente\"></el-option>\r\n                        <el-option value=\"date\" label=\"Fecha\"></el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-6 p-1 col-md-3\">\r\n                    <el-input @input=\"getRecordsInput\" v-if=\"typeSearch != 'date'\" v-model=\"value\"></el-input>\r\n                    <el-date-picker value-format=\"yyyy-MM-dd\" @change=\"getRecordsInput\" v-else\r\n                        v-model=\"value\"></el-date-picker>\r\n                </div>\r\n            </div>\r\n            <div class=\"d-flex align-items-center justify-content-end\">\r\n                <span class=\"p-1\">Ultimo documento emitido:\r\n                    {{    lastDocument    ? lastDocument.numberPrint                    : \"No se encontró\"                    }}</span>\r\n                <el-button class=\"btn btn-primary\" @click=\"\r\n                    printData(\r\n                        lastDocument.external_id,\r\n                        lastDocument.document_type_id\r\n                    )\r\n                \">\r\n                    <i class=\"fas fa-print\"></i>\r\n                </el-button>\r\n            </div>\r\n            <div>\r\n                <el-tabs v-model=\"activeName\" @tab-click=\"handleClick\">\r\n                    <el-tab-pane label=\"Notas de venta\" name=\"saleNotes\">\r\n                        <document-print-detail :company=\"company\" @getRecords=\"getRecords\" @printData=\"printData\"\r\n                            :records.sync=\"saleNotes\" :pagination.sync=\"pagination.saleNotes\" :type=\"'saleNotes'\"\r\n                            :sender=\"sender\">\r\n                        </document-print-detail>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane v-if=\"company.soap_type_id != '03'\" label=\"Facturas - Boletas\" name=\"documents\">\r\n                        <document-print-detail :sender=\"sender\" :company=\"company\" @getRecords=\"getRecords\"\r\n                            @printData=\"printData\" :records.sync=\"documents\" :pagination.sync=\"pagination.documents\"\r\n                            :type=\"'documents'\">\r\n                        </document-print-detail>\r\n                    </el-tab-pane>\r\n                </el-tabs>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n<style>\r\n    .el-dialog__header {\r\n        background-color: var(--primary) !important; \r\n    }\r\n    .el-dialog__title {\r\n        color: var(--light-text) !important;\r\n    }\r\n    .el-dialog__headerbtn .el-dialog__close{\r\n        color:white !important;\r\n    }\r\n</style>\r\n<script>\r\nimport DocumentPrintDetail from \"./document_print_detail.vue\";\r\nimport queryString from \"query-string\";\r\nexport default {\r\n    components: { DocumentPrintDetail },\r\n    props: [\"showDialog\", \"company\", \"sender\",\"config\", \"establishment\"],\r\n    data() {\r\n        return {\r\n            time: null,\r\n            loading: false,\r\n            value: null,\r\n            typeSearch: \"document\",\r\n            saleNotes: [],\r\n            documents: [],\r\n            pagination: {\r\n                saleNotes: {},\r\n                documents: {}\r\n            },\r\n            printer: null,\r\n            lastDocument: null,\r\n            activeName: \"documents\"\r\n        };\r\n    },\r\n    methods: {\r\n        getRecordsInput() {\r\n            this.getRecords();\r\n        },\r\n        async printEvent(url) {\r\n            \r\n            let paperConfig = {\r\n                scaleContent: false     \r\n            };\r\n            let partsUrl = url.split(\"/\");\r\n            let document = partsUrl[partsUrl.length - 1];\r\n            let isTicket = document.toLowerCase().includes(\"ticket\")\r\n           \r\n            let tipoBandejaImpresora = this.config.new_old_printer;\r\n\r\n            if (!isTicket && tipoBandejaImpresora == 1) {//opciones que permiten hacer una impresion correcta en impresoras nuevas\r\n                paperConfig.density = 600 ;\r\n                paperConfig.orientation= 'portrait';\r\n                paperConfig.margins = {left: 2}\r\n                }else if(!isTicket && tipoBandejaImpresora == 0){\r\n                paperConfig.density = 350 ;\r\n                paperConfig.orientation= 'portrait';\r\n                \r\n            }\r\n\r\n            try {\r\n                let config = qz.configs.create(this.printer, paperConfig);\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: url\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n            } catch (e) { }\r\n        },\r\n        async printData(external_id, type) {\r\n            let typePrint = this.establishment.format_printer\r\n            let url = \"\";\r\n            //colocar una condicion para cada caso desde impresira de 80mm hasta las a4 y a5\r\n            if(typePrint == '1'){//tamaño a4\r\n                if (type == \"80\") {\r\n                    url = `/sale-notes/print/${external_id}/a4`;\r\n                } else {\r\n                    url = `/print/document/${external_id}/a4`;\r\n                }\r\n            }\r\n            if(typePrint == '2'){//tamaño a5\r\n                if (type == \"80\") {\r\n                    url = `/sale-notes/print/${external_id}/a5`;\r\n                } else {\r\n                    url = `/print/document/${external_id}/a5`;\r\n                }\r\n            }   \r\n            if(typePrint == '3'){//tamaño 80mm\r\n                if (type == \"80\") {\r\n                    url = `/sale-notes/print/${external_id}/ticket`;\r\n                } else {\r\n                    url = `/print/document/${external_id}/ticket`;\r\n                }\r\n            }\r\n            if(typePrint == '4'){//tamaño 50mm\r\n                if (type == \"80\") {\r\n                    url = `/sale-notes/print/${external_id}/ticket_50`;\r\n                } else {\r\n                    url = `/print/document/${external_id}/ticket_50`;\r\n                }\r\n            }\r\n\r\n            await this.printEvent(url);\r\n        },\r\n        async getLastDocument() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(`print_last_document`);\r\n\r\n                if (response.status == 200) {\r\n                    const {\r\n                        data: { document }\r\n                    } = response;\r\n                    this.lastDocument = document;\r\n                    let filename = this.lastDocument.filename.split(\"-\");\r\n                    this.lastDocument.numberPrint =\r\n                        filename[2] + \"-\" + filename[3];\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"No se pudo obtener el ultimo documento\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async getPrinter() {\r\n            const response = await this.$http(\r\n                `cash/get_printer/${this.area_id}`\r\n            );\r\n\r\n            let {\r\n                data: { printer }\r\n            } = response;\r\n            this.printer = printer;\r\n        },\r\n        getRecords(page = 1) {\r\n            if (this.activeName == \"saleNotes\") {\r\n                this.pagination.saleNotes.current_page = Number(page);\r\n            } else {\r\n                this.pagination.documents.current_page = Number(page);\r\n            }\r\n            if (this.time) {\r\n                clearTimeout(this.time);\r\n            }\r\n            this.time = setTimeout(async () => {\r\n                await this.getLastDocuments();\r\n            }, 500);\r\n        },\r\n        getQueryParameters(form = {}) {\r\n            let page =\r\n                this.activeName == \"saleNotes\"\r\n                    ? this.pagination.saleNotes.current_page\r\n                    : this.pagination.documents.current_page;\r\n            return queryString.stringify({\r\n                page:\r\n                    this.activeName == \"saleNotes\"\r\n                        ? this.pagination.saleNotes.current_page\r\n                        : this.pagination.documents.current_page,\r\n                isNote: this.activeName == \"saleNotes\",\r\n                column: this.typeSearch,\r\n                value: this.value\r\n\r\n                // limit: this.limit\r\n            });\r\n        },\r\n        handleClick() {\r\n            if (this.saleNotes.length == 0 || this.documents.length == 0) {\r\n                this.getLastDocuments();\r\n            }\r\n        },\r\n        async open() {\r\n            await this.getLastDocument();\r\n            await this.getLastDocuments();\r\n            await this.getPrinter();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n\r\n        async getLastDocuments() {\r\n            //\"/sale-notes/print/{$doc->external_id}/ticket\r\n            //\"/print/document/{$doc->external_id}/ticket\";\r\n\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `cash/get_last_documents?${this.getQueryParameters()}`\r\n                );\r\n\r\n                if (response.status != 200) {\r\n                    this.$toast.error(\"No se pudo imprimir\");\r\n                } else {\r\n                    const { data, meta } = response.data;\r\n                    if (this.activeName == \"saleNotes\") {\r\n                        this.saleNotes = data;\r\n                        this.pagination.saleNotes = meta;\r\n                    } else {\r\n                        this.documents = data;\r\n                        this.pagination.documents = meta;\r\n                    }\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n                this.$toast.error(\"No se pudo imprimir\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/documents_print.vue","<template>\r\n    <el-dialog\r\n        append-to-body\r\n        v-loading=\"loading\"\r\n        title=\"Enviar documento por whatsapp\"\r\n        width=\"40%\"\r\n        :visible=\"showDialog\"\r\n    >\r\n        <div class=\"card \">\r\n            <div class=\"row d-flex align-items-center\">\r\n                <div class=\"col-8\">\r\n                    <el-input v-model=\"number\" placeholder=\"tlf: 999999999\">\r\n                    </el-input>\r\n                </div>\r\n                <div class=\"col-4\">\r\n                    <el-checkbox\r\n                        :disabled=\"documentTypeId == '80'\"\r\n                        v-model=\"withXml\"\r\n                    >\r\n                        Adjuntar XML\r\n                    </el-checkbox>\r\n                </div>\r\n            </div>\r\n            <div class=\"d-flex justify-content-end p-2\">\r\n                <el-button @click=\"sendFiles\" type=\"primary\">Enviar</el-button>\r\n                <el-button @click=\"close\">\r\n                    Cerrar\r\n                </el-button>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n<script>\r\nexport default {\r\n    props: [\r\n        \"showDialog\",\r\n        \"documentId\",\r\n        \"documentTypeId\",\r\n        \"company\",\r\n        \"documentNumber\",\r\n        \"sender\"\r\n    ],\r\n    data() {\r\n        return {\r\n            number: null,\r\n            withXml: false,\r\n            loading: false\r\n        };\r\n    },\r\n    methods: {\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.number = null;\r\n            this.withXml = false;\r\n        },\r\n        existNumber() {\r\n            let number = this.number;\r\n            if (!number.startsWith(\"9\")) {\r\n                return false;\r\n            }\r\n            if (number.length != 9) {\r\n                return false;\r\n            }\r\n            if (isNaN(Number(number))) {\r\n                return false;\r\n            }\r\n            return true;\r\n        },\r\n        async sendFiles() {\r\n            if (!this.number) {\r\n                this.$toast.warning(\"Ingrese un número\");\r\n                return;\r\n            }\r\n            if (!this.existNumber()) {\r\n                this.$toast.error(\"Número para envío whatsapp inválido\");\r\n                return;\r\n            }\r\n            let formWhatsapp = {\r\n                document_id: this.documentId,\r\n                document_type_id: this.documentTypeId,\r\n                customer_telephone: this.number,\r\n                sender: this.sender,\r\n                mensaje:\r\n                    \"Su comprobante de pago electrónico \" +\r\n                    this.documentNumber +\r\n                    \" de *\" +\r\n                    this.company.name +\r\n                    \"*, ha sido generado correctamente a través del facturador electrónico de *Sdrimsac Solutions*\"\r\n            };\r\n            try {\r\n                this.loading = true;\r\n                let response = await this.$http.post(`/whatsapp`, formWhatsapp);\r\n                if (this.withXml) {\r\n                    formWhatsapp.xml = true;\r\n                    response = await this.$http.post(`/whatsapp`, formWhatsapp);\r\n                }\r\n                if (response.status == 200) {\r\n                    this.$toast.success(\"El mensaje se envió correctamente\");\r\n                } else {\r\n                    this.$toast.error(\"Ocurrió un error en el envio\");\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Ocurrió un error en el envio\");\r\n            } finally {\r\n                this.loading = false;\r\n                this.close();\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/whatsapp_modal.vue","exports = module.exports = require(\"../../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.el-dialog__header {\\n    background-color: var(--primary) !important;\\n}\\n.el-dialog__title {\\n    color: var(--light-text) !important;\\n}\\n.el-dialog__headerbtn .el-dialog__close{\\n    color:white !important;\\n}\\n\", \"\", {\"version\":3,\"sources\":[\"D:/laragon/www/restobar/modules/Restaurant/Resources/assets/js/views/pos/partials/modules/Restaurant/Resources/assets/js/views/pos/partials/documents_print.vue\"],\"names\":[],\"mappings\":\";AAmDA;IACA,4CAAA;CACA;AACA;IACA,oCAAA;CACA;AACA;IACA,uBAAA;CACA\",\"file\":\"documents_print.vue\",\"sourcesContent\":[\"<template>\\r\\n    <el-dialog :visible=\\\"showDialog\\\" append-to-body @close=\\\"close\\\" @open=\\\"open\\\" width=\\\"60%\\\" v-loading=\\\"loading\\\"  \\r\\n        title=\\\"Imprimir documento\\\">\\r\\n        <div class=\\\"card p-2\\\">\\r\\n            <div class=\\\"d-flex\\\">\\r\\n                <div class=\\\"col-6 p-1 col-md-3\\\">\\r\\n                    <el-select v-model=\\\"typeSearch\\\">\\r\\n                        <el-option value=\\\"document\\\" label=\\\"N° documento\\\">\\r\\n                        </el-option>\\r\\n                        <el-option value=\\\"client\\\" label=\\\"Cliente\\\"></el-option>\\r\\n                        <el-option value=\\\"date\\\" label=\\\"Fecha\\\"></el-option>\\r\\n                    </el-select>\\r\\n                </div>\\r\\n                <div class=\\\"col-6 p-1 col-md-3\\\">\\r\\n                    <el-input @input=\\\"getRecordsInput\\\" v-if=\\\"typeSearch != 'date'\\\" v-model=\\\"value\\\"></el-input>\\r\\n                    <el-date-picker value-format=\\\"yyyy-MM-dd\\\" @change=\\\"getRecordsInput\\\" v-else\\r\\n                        v-model=\\\"value\\\"></el-date-picker>\\r\\n                </div>\\r\\n            </div>\\r\\n            <div class=\\\"d-flex align-items-center justify-content-end\\\">\\r\\n                <span class=\\\"p-1\\\">Ultimo documento emitido:\\r\\n                    {{    lastDocument    ? lastDocument.numberPrint                    : \\\"No se encontró\\\"                    }}</span>\\r\\n                <el-button class=\\\"btn btn-primary\\\" @click=\\\"\\r\\n                    printData(\\r\\n                        lastDocument.external_id,\\r\\n                        lastDocument.document_type_id\\r\\n                    )\\r\\n                \\\">\\r\\n                    <i class=\\\"fas fa-print\\\"></i>\\r\\n                </el-button>\\r\\n            </div>\\r\\n            <div>\\r\\n                <el-tabs v-model=\\\"activeName\\\" @tab-click=\\\"handleClick\\\">\\r\\n                    <el-tab-pane label=\\\"Notas de venta\\\" name=\\\"saleNotes\\\">\\r\\n                        <document-print-detail :company=\\\"company\\\" @getRecords=\\\"getRecords\\\" @printData=\\\"printData\\\"\\r\\n                            :records.sync=\\\"saleNotes\\\" :pagination.sync=\\\"pagination.saleNotes\\\" :type=\\\"'saleNotes'\\\"\\r\\n                            :sender=\\\"sender\\\">\\r\\n                        </document-print-detail>\\r\\n                    </el-tab-pane>\\r\\n                    <el-tab-pane v-if=\\\"company.soap_type_id != '03'\\\" label=\\\"Facturas - Boletas\\\" name=\\\"documents\\\">\\r\\n                        <document-print-detail :sender=\\\"sender\\\" :company=\\\"company\\\" @getRecords=\\\"getRecords\\\"\\r\\n                            @printData=\\\"printData\\\" :records.sync=\\\"documents\\\" :pagination.sync=\\\"pagination.documents\\\"\\r\\n                            :type=\\\"'documents'\\\">\\r\\n                        </document-print-detail>\\r\\n                    </el-tab-pane>\\r\\n                </el-tabs>\\r\\n            </div>\\r\\n        </div>\\r\\n    </el-dialog>\\r\\n</template>\\r\\n<style>\\r\\n    .el-dialog__header {\\r\\n        background-color: var(--primary) !important; \\r\\n    }\\r\\n    .el-dialog__title {\\r\\n        color: var(--light-text) !important;\\r\\n    }\\r\\n    .el-dialog__headerbtn .el-dialog__close{\\r\\n        color:white !important;\\r\\n    }\\r\\n</style>\\r\\n<script>\\r\\nimport DocumentPrintDetail from \\\"./document_print_detail.vue\\\";\\r\\nimport queryString from \\\"query-string\\\";\\r\\nexport default {\\r\\n    components: { DocumentPrintDetail },\\r\\n    props: [\\\"showDialog\\\", \\\"company\\\", \\\"sender\\\",\\\"config\\\", \\\"establishment\\\"],\\r\\n    data() {\\r\\n        return {\\r\\n            time: null,\\r\\n            loading: false,\\r\\n            value: null,\\r\\n            typeSearch: \\\"document\\\",\\r\\n            saleNotes: [],\\r\\n            documents: [],\\r\\n            pagination: {\\r\\n                saleNotes: {},\\r\\n                documents: {}\\r\\n            },\\r\\n            printer: null,\\r\\n            lastDocument: null,\\r\\n            activeName: \\\"documents\\\"\\r\\n        };\\r\\n    },\\r\\n    methods: {\\r\\n        getRecordsInput() {\\r\\n            this.getRecords();\\r\\n        },\\r\\n        async printEvent(url) {\\r\\n            \\r\\n            let paperConfig = {\\r\\n                scaleContent: false     \\r\\n            };\\r\\n            let partsUrl = url.split(\\\"/\\\");\\r\\n            let document = partsUrl[partsUrl.length - 1];\\r\\n            let isTicket = document.toLowerCase().includes(\\\"ticket\\\")\\r\\n           \\r\\n            let tipoBandejaImpresora = this.config.new_old_printer;\\r\\n\\r\\n            if (!isTicket && tipoBandejaImpresora == 1) {//opciones que permiten hacer una impresion correcta en impresoras nuevas\\r\\n                paperConfig.density = 600 ;\\r\\n                paperConfig.orientation= 'portrait';\\r\\n                paperConfig.margins = {left: 2}\\r\\n                }else if(!isTicket && tipoBandejaImpresora == 0){\\r\\n                paperConfig.density = 350 ;\\r\\n                paperConfig.orientation= 'portrait';\\r\\n                \\r\\n            }\\r\\n\\r\\n            try {\\r\\n                let config = qz.configs.create(this.printer, paperConfig);\\r\\n                if (!qz.websocket.isActive()) {\\r\\n                    await qz.websocket.connect(config);\\r\\n                }\\r\\n                let data = [\\r\\n                    {\\r\\n                        type: \\\"pdf\\\",\\r\\n                        format: \\\"file\\\",\\r\\n                        data: url\\r\\n                    }\\r\\n                ];\\r\\n                qz.print(config, data).catch(e => {\\r\\n                    this.$toast.error(e.message);\\r\\n                });\\r\\n            } catch (e) { }\\r\\n        },\\r\\n        async printData(external_id, type) {\\r\\n            let typePrint = this.establishment.format_printer\\r\\n            let url = \\\"\\\";\\r\\n            //colocar una condicion para cada caso desde impresira de 80mm hasta las a4 y a5\\r\\n            if(typePrint == '1'){//tamaño a4\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/a4`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/a4`;\\r\\n                }\\r\\n            }\\r\\n            if(typePrint == '2'){//tamaño a5\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/a5`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/a5`;\\r\\n                }\\r\\n            }   \\r\\n            if(typePrint == '3'){//tamaño 80mm\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/ticket`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/ticket`;\\r\\n                }\\r\\n            }\\r\\n            if(typePrint == '4'){//tamaño 50mm\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/ticket_50`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/ticket_50`;\\r\\n                }\\r\\n            }\\r\\n\\r\\n            await this.printEvent(url);\\r\\n        },\\r\\n        async getLastDocument() {\\r\\n            try {\\r\\n                this.loading = true;\\r\\n                const response = await this.$http(`print_last_document`);\\r\\n\\r\\n                if (response.status == 200) {\\r\\n                    const {\\r\\n                        data: { document }\\r\\n                    } = response;\\r\\n                    this.lastDocument = document;\\r\\n                    let filename = this.lastDocument.filename.split(\\\"-\\\");\\r\\n                    this.lastDocument.numberPrint =\\r\\n                        filename[2] + \\\"-\\\" + filename[3];\\r\\n                }\\r\\n            } catch (e) {\\r\\n                this.$toast.error(\\\"No se pudo obtener el ultimo documento\\\");\\r\\n            } finally {\\r\\n                this.loading = false;\\r\\n            }\\r\\n        },\\r\\n        async getPrinter() {\\r\\n            const response = await this.$http(\\r\\n                `cash/get_printer/${this.area_id}`\\r\\n            );\\r\\n\\r\\n            let {\\r\\n                data: { printer }\\r\\n            } = response;\\r\\n            this.printer = printer;\\r\\n        },\\r\\n        getRecords(page = 1) {\\r\\n            if (this.activeName == \\\"saleNotes\\\") {\\r\\n                this.pagination.saleNotes.current_page = Number(page);\\r\\n            } else {\\r\\n                this.pagination.documents.current_page = Number(page);\\r\\n            }\\r\\n            if (this.time) {\\r\\n                clearTimeout(this.time);\\r\\n            }\\r\\n            this.time = setTimeout(async () => {\\r\\n                await this.getLastDocuments();\\r\\n            }, 500);\\r\\n        },\\r\\n        getQueryParameters(form = {}) {\\r\\n            let page =\\r\\n                this.activeName == \\\"saleNotes\\\"\\r\\n                    ? this.pagination.saleNotes.current_page\\r\\n                    : this.pagination.documents.current_page;\\r\\n            return queryString.stringify({\\r\\n                page:\\r\\n                    this.activeName == \\\"saleNotes\\\"\\r\\n                        ? this.pagination.saleNotes.current_page\\r\\n                        : this.pagination.documents.current_page,\\r\\n                isNote: this.activeName == \\\"saleNotes\\\",\\r\\n                column: this.typeSearch,\\r\\n                value: this.value\\r\\n\\r\\n                // limit: this.limit\\r\\n            });\\r\\n        },\\r\\n        handleClick() {\\r\\n            if (this.saleNotes.length == 0 || this.documents.length == 0) {\\r\\n                this.getLastDocuments();\\r\\n            }\\r\\n        },\\r\\n        async open() {\\r\\n            await this.getLastDocument();\\r\\n            await this.getLastDocuments();\\r\\n            await this.getPrinter();\\r\\n        },\\r\\n        close() {\\r\\n            this.$emit(\\\"update:showDialog\\\", false);\\r\\n        },\\r\\n\\r\\n        async getLastDocuments() {\\r\\n            //\\\"/sale-notes/print/{$doc->external_id}/ticket\\r\\n            //\\\"/print/document/{$doc->external_id}/ticket\\\";\\r\\n\\r\\n            try {\\r\\n                this.loading = true;\\r\\n                const response = await this.$http(\\r\\n                    `cash/get_last_documents?${this.getQueryParameters()}`\\r\\n                );\\r\\n\\r\\n                if (response.status != 200) {\\r\\n                    this.$toast.error(\\\"No se pudo imprimir\\\");\\r\\n                } else {\\r\\n                    const { data, meta } = response.data;\\r\\n                    if (this.activeName == \\\"saleNotes\\\") {\\r\\n                        this.saleNotes = data;\\r\\n                        this.pagination.saleNotes = meta;\\r\\n                    } else {\\r\\n                        this.documents = data;\\r\\n         